#!/usr/bin/env python3
"""Run `pnpm lint` before any `git commit`; block the commit if lint fails."""
import json, os, re, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not re.search(r"\bgit\s+commit\b", cmd):
        return 0
    project = os.environ.get("CLAUDE_PROJECT_DIR", ".")
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            cwd=project,
            capture_output=True,
            text=True,
            timeout=120,
        )
    except Exception as e:
        print(
            f"BLOCKING: pre-commit `pnpm lint` failed to execute ({e}). "
            "Fix the lint environment, then retry the commit. Do not skip lint.",
            file=sys.stderr,
        )
        return 2
    if r.returncode != 0:
        out = (r.stdout + r.stderr).strip()[:3000]
        print(
            "BLOCKING: `pnpm lint` failed. Fix each lint error below, then retry the commit. Do not skip lint.",
            file=sys.stderr,
        )
        if out:
            print(out, file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

