#!/usr/bin/env python3
"""Block Edit/Write/MultiEdit on .py files that introduce a function which
calls itself directly. walk_tree was rewritten recursively and blew the stack
on a 2000-leaf tree; flag the pattern repo-wide so the rewrite never lands."""
import json, re, sys


def find_self_recursive(source: str) -> list[str]:
    hits: list[str] = []
    lines = source.splitlines()
    i = 0
    while i < len(lines):
        m = re.match(r"^(\s*)def\s+(\w+)\s*\(", lines[i])
        if not m:
            i += 1
            continue
        indent = len(m.group(1))
        name = m.group(2)
        body: list[str] = []
        j = i + 1
        while j < len(lines):
            line = lines[j]
            if not line.strip():
                body.append(line)
                j += 1
                continue
            line_indent = len(line) - len(line.lstrip())
            if line_indent <= indent:
                break
            body.append(line)
            j += 1
        body_text = "\n".join(body)
        if re.search(rf"\b{re.escape(name)}\s*\(", body_text):
            hits.append(name)
        i = j if j > i else i + 1
    return hits


def main() -> int:
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit", "Write"):
        return 0
    inp = ev.get("tool_input") or {}
    fp = inp.get("file_path", "")
    if not fp.endswith(".py"):
        return 0
    tool = ev.get("tool_name")
    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "MultiEdit":
        content = "\n".join(e.get("new_string", "") for e in (inp.get("edits") or []))
    else:
        content = inp.get("new_string", "")
    hits = find_self_recursive(content)
    if hits:
        names = ", ".join(sorted(set(hits)))
        print(f"BLOCKING: {fp} introduces self-recursive function(s): {names}.", file=sys.stderr)
        print("Python's default recursion limit (~1000) blew the stack on this tree-walking codebase before. Rewrite to iteration with an explicit stack/queue, or add a depth bound that raises before sys.getrecursionlimit. Re-issue the edit without unbounded recursion.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/Write/MultiEdit on a .py file, run `ruff format` then `ruff check`.
Surface reformatting and lint findings so Claude re-reads and fixes them."""
import json
import subprocess
import sys
from pathlib import Path


def _run(args):
    try:
        return subprocess.run(args, capture_output=True, text=True, timeout=10)
    except Exception:
        return None


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name", "") not in ("Edit", "Write", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    fp = inp.get("file_path", "")
    if not fp.endswith(".py") or not Path(fp).is_file():
        return 0

    fmt = _run(["ruff", "format", fp])
    chk = _run(["ruff", "check", fp])

    msgs = []
    if fmt is not None:
        out = (fmt.stderr or "") + (fmt.stdout or "")
        if "reformatted" in out.lower():
            msgs.append(f"ruff format reformatted {fp} - re-read before further edits.")
    if chk is not None and chk.returncode != 0:
        msgs.append(f"ruff check found issues in {fp}:")
        for line in ((chk.stdout or "") + (chk.stderr or "")).splitlines()[:20]:
            msgs.append(f"  {line}")

    if msgs:
        print("REQUIRED FOLLOW-UP:", file=sys.stderr)
        for m in msgs:
            print(m, file=sys.stderr)
        print("Fix each, then proceed. Do not stop. Do not ask.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on an exported identifier definition, grep for callers
(by identifier name AND by old literal value if it changed) so Claude must
reconcile stale references before stopping."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)
EXPORT_LIT = re.compile(
    r"export\s+(?:const|let|var)\s+(\w+)[^=]*=\s*(['\"`])([^'\"`]+)\2"
)


def grep(token, label, hits):
    try:
        r = subprocess.run(
            ["grep", "-rnF", "--include=*.ts", "--include=*.tsx",
             "--include=*.js", "--include=*.jsx", token, "."],
            capture_output=True, text=True, timeout=5,
        )
        for h in [l for l in r.stdout.splitlines() if l][:15]:
            hits.append(f"  [{label}] {h}")
    except Exception:
        pass


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names, old_vals = set(), set()
    for e in edits:
        old_s, new_s = e.get("old_string", ""), e.get("new_string", "")
        for s in (old_s, new_s):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))
        om = EXPORT_LIT.search(old_s)
        nm = EXPORT_LIT.search(new_s)
        if om and nm and om.group(1) == nm.group(1) and om.group(3) != nm.group(3):
            old_vals.add(om.group(3))

    if not names and not old_vals:
        return 0

    hits = []
    for n in names:
        grep(n, f"name:{n}", hits)
    for v in old_vals:
        grep(f"'{v}'", f"value:'{v}'", hits)
        grep(f'"{v}"', f'value:"{v}"', hits)

    if hits:
        labels = sorted(names) + [f"value='{v}'" for v in sorted(old_vals)]
        print(
            f"BLOCKING: exported {', '.join(labels)} edited; "
            f"{len(hits)} stale references remain:",
            file=sys.stderr,
        )
        for h in hits:
            print(h, file=sys.stderr)
        print("Fix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

# Block Write/Edit/MultiEdit that introduce hardcoded API keys or secrets.
import json, re, sys

SECRET_RE = re.compile(
    r"(?<!\w)sk-(?:proj-|ant-)?[A-Za-z0-9_\-]{20,}"
    r"|(?<!\w)AKIA[0-9A-Z]{16}|(?<!\w)ASIA[0-9A-Z]{16}"
    r"|(?<!\w)AIza[0-9A-Za-z_\-]{35}"
    r"|(?<!\w)gh[posu]_[A-Za-z0-9]{36,}|(?<!\w)github_pat_[A-Za-z0-9_]{22,}"
    r"|(?<!\w)xox[baprs]-[A-Za-z0-9\-]{10,}"
    r"|-----BEGIN (?:RSA |EC |OPENSSH )?PRIVATE KEY-----"
)
ASSIGN_RE = re.compile(
    r"(?i)(?:api[_-]?key|secret|token|password|passwd|access[_-]?key|"
    r"client[_-]?secret|auth[_-]?token|bearer)"
    r"""\s*[:=]\s*['\"`](?P<val>[A-Za-z0-9_\-/+=]{16,})['\"`]"""
)
PLACEHOLDER = re.compile(
    r"^(?:x{3,}|\*{3,}|<.+>|\$\{.+\}|process\.env|placeholder|"
    r"example|test|dummy|fake|todo|change[_-]?me)$", re.I
)
SAFE_PATH = re.compile(
    r"(?:^|/)(?:\.env\.(?:example|sample|template)|fixtures?/|__fixtures__/|test[_-]?data/)"
)

def text_for(tool, inp):
    if tool == "Write": return inp.get("content", "") or ""
    if tool == "Edit": return inp.get("new_string", "") or ""
    if tool == "MultiEdit":
        return "\n".join((e.get("new_string", "") or "") for e in (inp.get("edits") or []))
    return ""

def find_hits(text):
    hits = []
    if SECRET_RE.search(text):
        hits.append("known-prefix secret (e.g. sk-/AKIA/ghp_/AIza/xox*/private key)")
    for m in ASSIGN_RE.finditer(text):
        if not PLACEHOLDER.match(m.group("val")):
            hits.append(f"literal in secret-named field: `{m.group(0)[:60]}`")
    return hits

def main():
    try: ev = json.load(sys.stdin)
    except Exception: return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"): return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "") or ""
    if SAFE_PATH.search(path): return 0
    hits = find_hits(text_for(tool, inp))
    if hits:
        print("BLOCKING: refusing to write a hardcoded secret into source.", file=sys.stderr)
        print(f"  file: {path}", file=sys.stderr)
        for h in sorted(set(hits)):
            print(f"  detected: {h}", file=sys.stderr)
        print("Read the secret from process.env (e.g. `process.env.OPENAI_API_KEY`) and document the variable in .env.example. Do not paste literal keys. Do not ask.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

