#!/usr/bin/env python3
"""After Edit/MultiEdit/Write on a .py file, statically check for syntax
errors and undefined names (file-scoped union, conservative) and surface
issues to Claude as a blocking imperative. No external deps required."""
import ast, builtins, json, os, sys


MODULE_DUNDERS = {
    "__name__", "__file__", "__doc__", "__package__", "__loader__",
    "__spec__", "__builtins__", "__path__", "__all__", "__version__",
    "__author__", "__cached__",
}


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit", "Write"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path") or ""
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0

    try:
        src = open(path, encoding="utf-8").read()
    except Exception:
        return 0
    try:
        tree = ast.parse(src, filename=path)
    except SyntaxError as e:
        print(f"BLOCKING: syntax error in {path} (line {e.lineno}): {e.msg}", file=sys.stderr)
        print("Fix the error, then continue. Do not stop. Do not ask.", file=sys.stderr)
        return 2

    defined = set(dir(builtins)) | MODULE_DUNDERS
    for n in ast.walk(tree):
        if isinstance(n, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            defined.add(n.name)
        elif isinstance(n, ast.arg):
            defined.add(n.arg)
        elif isinstance(n, ast.alias):
            defined.add(n.asname or n.name.split(".")[0])
        elif isinstance(n, ast.Name) and isinstance(n.ctx, ast.Store):
            defined.add(n.id)
        elif isinstance(n, ast.ExceptHandler) and n.name:
            defined.add(n.name)
        elif isinstance(n, (ast.Global, ast.Nonlocal)):
            for name in n.names:
                defined.add(name)

    undefined = []
    for n in ast.walk(tree):
        if isinstance(n, ast.Name) and isinstance(n.ctx, ast.Load) and n.id not in defined:
            undefined.append((n.lineno, n.id))

    if undefined:
        print(f"BLOCKING: undefined name(s) in {path}:", file=sys.stderr)
        for line, name in undefined[:10]:
            print(f"  line {line}: '{name}' not defined in this file", file=sys.stderr)
        print("Fix each, then continue. Do not stop. Do not ask.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
